mapper.delete:
  		/* 구매자 주문이력 삭제 */
  		delete 
		from
			orders 
		where
			cust_id  = #{customerId};

  		/* 판매자가 등록한 상품을 구매한 이력 삭제 */
		delete 
		   oi
		FROM
		    vendors v inner join products p 
		    using (vend_cd)
		    inner join orderitems oi
		    on p.prod_cd = oi.order_prod_cd 
		WHERE
		    v.vend_mbr_id = #{sellerId};
